external_knowledge:
- 'captains' refers to users with the role of 'researcher';
- 'sail through the vast lakes' refers to sampling sites where the water body type is 'lake';
- 'riding high above the clouds' means the elevation of the site is above 1000 meters;
- 'validations glowing like the stars, shining brighter than ninety percent' indicates a validation success rate greater than 90%;
- 'coordinates of their voyages' refer to the latitude and longitude of the sampling sites.

sql:
SELECT validation_status, COUNT(*) as count
FROM data_validations
GROUP BY validation_status;

SELECT DISTINCT username
FROM users
JOIN data_validations ON users.user_id = data_validations.validator_id;

SELECT site_name, location
FROM sampling_sites
WHERE active_status = 1;

SELECT COUNT(*)
FROM data_validations
WHERE validator_id = (SELECT user_id FROM users WHERE username = 'Your_Username');

SELECT COUNT(site_id) AS Active_Sites_Count, AVG(elevation) AS Average_Elevation
FROM sampling_sites
WHERE active_status = 1 AND water_body_type = 'lake';
